class AccountingStandardEnum(Enum):
    """
    The type of accounting standard applied.

    :cvar GAAP: Indicates that the accounting standards observed are the
        generally accepted accounting principles.
    :cvar IFRS: Indicates that the accounting standards observed are the
        International Financial Reporting Standards.
    """

    GAAP = "GAAP"
    IFRS = "IFRS"


class AccrualReferenceAmountTypeEnum(Enum):
    """
    The type of amount referenced by the accrual.

    :cvar COMMITMENT: The accrual is calculated using the facility
        commitment amount as the reference amount.
    :cvar FUNDED: The accrual is calculated using the facility total
        funded amount as the reference amount.
    :cvar OTHER: The accrual is calculated using another type of
        (calculated) reference amount.
    :cvar UNFUNDED: The accrual is calculated using the total facility
        unfunded amount as the reference amount. The unfunded amount
        refers to the amount of commitment which has been utilized with
        unfunded products (e.g. L/Cs).
    :cvar UNUTILIZED: The accrual is calculated using the facility total
        unutilized amount as the reference amount. The unutilized amount
        refers to the amount of commitment which has not yet been
        borrowed.
    :cvar UTILIZED: The accrual is calculated using the facility total
        utilized amount as the reference amount. The utilized amount
        includes both funded and unfunded borrowings.
    """

    COMMITMENT = "Commitment"
    FUNDED = "Funded"
    OTHER = "Other"
    UNFUNDED = "Unfunded"
    UNUTILIZED = "Unutilized"
    UTILIZED = "Utilized"


