@dataclass(kw_only=True)
class AdditionalFixedPayments:
    """
    :ivar interest_shortfall_reimbursement: An additional Fixed Payment
        Event. Corresponds to the payment by or on behalf of the Issuer
        of an actual interest amount in respect to the reference
        obligation that is greater than the expected interest amount.
        ISDA 2003 Term: Interest Shortfall Reimbursement.
    :ivar principal_shortfall_reimbursement: An additional Fixed Payment
        Event. Corresponds to the payment by or on behalf of the Issuer
        of an actual principal amount in respect to the reference
        obligation that is greater than the expected principal amount.
        ISDA 2003 Term: Principal Shortfall Reimbursement.
    :ivar writedown_reimbursement: An Additional Fixed Payment.
        Corresponds to the payment by or on behalf of the issuer of an
        amount in respect to the reference obligation in reduction of
        the prior writedowns. ISDA 2003 Term: Writedown Reimbursement.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    interest_shortfall_reimbursement: None | bool = field(
        default=None,
        metadata={
            "name": "interestShortfallReimbursement",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    principal_shortfall_reimbursement: None | bool = field(
        default=None,
        metadata={
            "name": "principalShortfallReimbursement",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    writedown_reimbursement: None | bool = field(
        default=None,
        metadata={
            "name": "writedownReimbursement",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


