@dataclass(kw_only=True)
class AdmissionToTrading:
    """
    Information about whether and when a product was admitted to trading on
    a facility.

    :ivar requested: Whether the issuer of the financial instrument has
        requested or approved the trading or admission to trading of
        their financial instruments on a trading venue.
    :ivar request_date: Date and time of the request for admission to
        trading on the trading venue.
    :ivar approval_date: Date and time the issuer has approved admission
        to trading or trading in its financial instruments on a trading
        venue.
    :ivar admission_date: Date and time of the admission to trading on
        the trading venue or the date and time when the instrument was
        first traded or an order or quote was first received by the
        trading venue.
    :ivar termination_date: Date and time when the financial instrument
        ceases to be traded or to be admitted to trading on the trading
        venue.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    requested: bool = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    request_date: None | XmlDateTime = field(
        default=None,
        metadata={
            "name": "requestDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    approval_date: None | XmlDateTime = field(
        default=None,
        metadata={
            "name": "approvalDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    admission_date: None | XmlDateTime = field(
        default=None,
        metadata={
            "name": "admissionDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    termination_date: None | XmlDateTime = field(
        default=None,
        metadata={
            "name": "terminationDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


