class AveragingInOutEnum(Enum):
    """
    The type of averaging used in an Asian option.

    :cvar IN: The average price is used to derive the strike price. Also
        known as "Asian strike" style option.
    :cvar OUT: The average price is used to derive the expiration price.
        Also known as "Asian price" style option.
    :cvar BOTH: The average price is used to derive both the strike and
        the expiration price.
    """

    IN = "In"
    OUT = "Out"
    BOTH = "Both"


class AveragingMethodEnum(Enum):
    """
    The method of calculation to be used when averaging rates.

    Per ISDA 2000 Definitions, Section 6.2. Certain Definitions Relating to
    Floating Amounts.

    :cvar UNWEIGHTED: The arithmetic mean of the relevant rates for each
        reset date.
    :cvar WEIGHTED: The arithmetic mean of the relevant rates in effect
        for each day in a calculation period calculated by multiplying
        each relevant rate by the number of days such relevant rate is
        in effect, determining the sum of such products and dividing
        such sum by the number of days in the calculation period.
    """

    UNWEIGHTED = "Unweighted"
    WEIGHTED = "Weighted"


