class BullionTypeEnum(Enum):
    """
    Defines which type of bullion is applicable for a Bullion Transaction.

    :cvar GOLD: Gold. Quality as per the Good Delivery Rules issued by
        the London Bullion Market Association.
    :cvar PALLADIUM: Palladium. Quality as per the Good Delivery Rules
        issued by the London Platinum and Palladium Market.
    :cvar PLATINUM: Palladium. Quality as per the Good Delivery Rules
        issued by the London Platinum and Palladium Market.
    :cvar SILVER: Silver. Quality as per the Good Delivery Rules issued
        by the London Bullion Market Association.
    :cvar RHODIUM: Quality as per the Good Delivery Rules for Rhodium.
    :cvar RHODIUM_SPONGE: DEPRECATED value which will be removed in
        FpML-6-0 onwards. Quality as per the Good Delivery Rules for
        Rhodium (Sponge) is too specific.
    :cvar IRIDIUM: Quality as per the Good Delivery Rules for Iridium.
    :cvar RUTHENIUM: Quality as per the Good Delivery Rules for
        Ruthenium.
    :cvar OSMIUM: Quality as per the Good Delivery Rules for Osmium.
    """

    GOLD = "Gold"
    PALLADIUM = "Palladium"
    PLATINUM = "Platinum"
    SILVER = "Silver"
    RHODIUM = "Rhodium"
    RHODIUM_SPONGE = "RhodiumSponge"
    IRIDIUM = "Iridium"
    RUTHENIUM = "Ruthenium"
    OSMIUM = "Osmium"


