class CalculationAgentPartyEnum(Enum):
    """
    The specification of how a calculation agent will be determined.

    :cvar EXERCISING_PARTY: The party that gives notice of exercise. Per
        2000 ISDA Definitions, Section 11.1. Parties, paragraph (d).
    :cvar NON_EXERCISING_PARTY: The party that is given notice of
        exercise. Per 2000 ISDA Definitions, Section 11.1. Parties,
        paragraph (e).
    :cvar AS_SPECIFIED_IN_MASTER_AGREEMENT: The Calculation Agent is
        determined by reference to the relevant master agreement.
    :cvar AS_SPECIFIED_IN_STANDARD_TERMS_SUPPLEMENT: The Calculation
        Agent is determined by reference to the relevant standard terms
        supplement.
    :cvar BOTH: Both parties with joined rights to be a calculation
        agent.
    """

    EXERCISING_PARTY = "ExercisingParty"
    NON_EXERCISING_PARTY = "NonExercisingParty"
    AS_SPECIFIED_IN_MASTER_AGREEMENT = "AsSpecifiedInMasterAgreement"
    AS_SPECIFIED_IN_STANDARD_TERMS_SUPPLEMENT = (
        "AsSpecifiedInStandardTermsSupplement"
    )
    BOTH = "Both"


class CalculationMethodEnum(Enum):
    """
    The type of calculation formula to use when combining multiple rates.

    :cvar AVERAGING: The resulting value is based on the weighted
        arithmetic average of the observations performed by the
        calculation agent. These are described in the 2021 ISDA
        Definitions in Section 7.4
    :cvar COMPOUNDING: The resulting value is based on a geometric
        averaging formula which is based on the multiplying the weighted
        daily rates. It is calculated by the calculation agent. These
        are described in the 2021 ISDA Definitions in Section 7.3
    :cvar COMPOUNDED_INDEX: The resulting value is based on a compounded
        index calculated by the rate administrator. The calculation
        agent is responsible for backing out the implied rate by
        calculating (final_index_level/initial_index_level - 1) /
        yearFraction. This calculation is described in Supplement 76 to
        the 2006 ISDA Definitions, for example in section 6.15, and in
        the 2021 ISDA Definitions in section 7.7.2 and 7.7.3.
    """

    AVERAGING = "Averaging"
    COMPOUNDING = "Compounding"
    COMPOUNDED_INDEX = "CompoundedIndex"


