class CommodityDayTypeEnum(Enum):
    """
    A day type classification used in counting the number of days between
    two dates for a commodity transaction.

    :cvar BUSINESS: When calculating the number of days between two
        dates the count includes only business days.
    :cvar CALENDAR: When calculating the number of days between two
        dates the count includes all calendar days.
    :cvar COMMODITY_BUSINESS: When calculating the number of days
        between two dates the count includes only commodity business
        days.
    :cvar CURRENCY_BUSINESS: When calculating the number of days between
        two dates the count includes only currency business days.
    :cvar EXCHANGE_BUSINESS: When calculating the number of days between
        two dates the count includes only stock exchange business days.
    :cvar SCHEDULED_TRADING_DAY: When calculating the number of days
        between two dates the count includes only scheduled trading
        days.
    :cvar GAS_FLOW: When calculating the number of days between two
        dates the count includes only gas flow days (dates on which gas
        is delivered).
    :cvar NEARBY_CONTRACT_DAY: The days that are starting from the end
        of the prior nearby futures/option contract through the nearby
        futures/option contract as specified in the message. For
        example: If referring to the Z21 WTI contract, first day of this
        type will be 21-Oct-21 and the last day of this type will be
        19-Nov-21.
    """

    BUSINESS = "Business"
    CALENDAR = "Calendar"
    COMMODITY_BUSINESS = "CommodityBusiness"
    CURRENCY_BUSINESS = "CurrencyBusiness"
    EXCHANGE_BUSINESS = "ExchangeBusiness"
    SCHEDULED_TRADING_DAY = "ScheduledTradingDay"
    GAS_FLOW = "GasFlow"
    NEARBY_CONTRACT_DAY = "NearbyContractDay"


