class CommodityPayRelativeToEnum(Enum):
    """
    The Commodity specification of whether payments occur relative e.g. to
    the Trade Date, or the end of the month, etc.

    :cvar CALCULATION_PERIOD_START_DATE: Payments will occur relative to
        the first day of each calculation period.
    :cvar CALCULATION_PERIOD_END_DATE: Payments will occur relative to
        the last day of each calculation period.
    :cvar LAST_PRICING_DATE: Payments will occur relative to the last
        Pricing Date of each Calculation Period.
    :cvar RESET_DATE: Payments will occur relative to the reset date.
    :cvar VALUATION_DATE: Payments will occur relative to the valuation
        date.
    :cvar CALCULATION_DATE: Payments will occur relative to the
        Calculation Date.
    :cvar CALCULATION_PERIOD_MONTH_END: Payments will occur relative to
        the end of the month date for Calculation Periods which do not
        end on the last day of the month.
    :cvar CALCULATION_PERIOD_MONTH_START: Payments will occur relative
        to the start of the month date for Calculation Periods which do
        not begin on the first day of the month.
    :cvar EFFECTIVE_DATE: Payments will occur relative to the Effective
        Date of the contract.
    :cvar PRICING_PERIOD_MONTH_END: Payments will occur relative to the
        end of the month date for the month in which Pricing Days occur.
    :cvar TERMINATION_OR_EXPIRATION_DATE: Payments will occur relative
        to the Termination Date of a swap or the last Expiration Date of
        an option.
    :cvar TRADE_DATE: Payments will occur relative to the Trade Date.
    :cvar PRICING_PERIOD_END_OF_WEEK: Payments will occur relative to
        end of each week relative to the pricing period.
    :cvar FIRST_PRICING_DATE: Payments will occur relative to the first
        pricing date of each calculation period.
    """

    CALCULATION_PERIOD_START_DATE = "CalculationPeriodStartDate"
    CALCULATION_PERIOD_END_DATE = "CalculationPeriodEndDate"
    LAST_PRICING_DATE = "LastPricingDate"
    RESET_DATE = "ResetDate"
    VALUATION_DATE = "ValuationDate"
    CALCULATION_DATE = "CalculationDate"
    CALCULATION_PERIOD_MONTH_END = "CalculationPeriodMonthEnd"
    CALCULATION_PERIOD_MONTH_START = "CalculationPeriodMonthStart"
    EFFECTIVE_DATE = "EffectiveDate"
    PRICING_PERIOD_MONTH_END = "PricingPeriodMonthEnd"
    TERMINATION_OR_EXPIRATION_DATE = "TerminationOrExpirationDate"
    TRADE_DATE = "TradeDate"
    PRICING_PERIOD_END_OF_WEEK = "PricingPeriodEndOfWeek"
    FIRST_PRICING_DATE = "FirstPricingDate"


