@dataclass(kw_only=True)
class Document:
    """
    The abstract base type from which all FpML compliant messages and
    documents must be derived.

    :ivar fpml_version: Indicate which version of the FpML Schema an
        FpML message adheres to.
    :ivar expected_build: This optional attribute can be supplied by a
        message creator in an FpML instance to specify which build
        number of the schema was used to define the message when it was
        generated.
    :ivar actual_build: The specific build number of this schema
        version. This attribute is not included in an instance document.
        Instead, it is supplied by the XML parser when the document is
        validated against the FpML schema and indicates the build number
        of the schema file. Every time FpML publishes a change to the
        schema, validation rules, or examples within a version (e.g.,
        version 4.2) the actual build number is incremented. If no
        changes have been made between releases within a version (i.e.
        from Trial Recommendation to Recommendation) the actual build
        number stays the same.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    fpml_version: str = field(
        metadata={
            "name": "fpmlVersion",
            "type": "Attribute",
            "min_length": 0,
            "pattern": r"5-(0|[1-9][0-9]{0,2})",
        }
    )
    expected_build: None | int = field(
        default=None,
        metadata={
            "name": "expectedBuild",
            "type": "Attribute",
        },
    )
    actual_build: int = field(
        init=False,
        default=4,
        metadata={
            "name": "actualBuild",
            "type": "Attribute",
        },
    )


