class EnvironmentalProductTypeEnum(Enum):
    """
    Environmental Product (e.g. allowance, certificate or unit).

    :cvar EUALLOWANCE: For EU Emissions Allowance Transactions: An EU
        Emissions Allowance.
    :cvar EUCREDIT: For EU Emissions Allowance Transactions: An EU
        Emissions Credit.
    :cvar ALTERNATIVE_ALLOWANCE: For EU Emissions Allowance
        Transactions: An EU Alternative Allowance.
    :cvar NOXEMISSIONS_PRODUCT: For US Emissions Allowance Transactions:
        A limited authorization issued by the state permitting authority
        or the US Environmental Protection Agency (EPA) to emit certain
        amounts of nitrogen oxides (Nox).
    :cvar REGIONAL_EMISSIONS_PRODUCT: For US Emissions Allowance
        Transactions: A emissions allowance or emissions reduction
        credit issued under a mult-state or provincial or other cap-and-
        trade Scheme.
    :cvar RGGIEMISSIONS_PRODUCT: For US Emissions Allowance
        Transactions: A limited authorization issued by the RGGI scheme
        permitting the emission of certain amounts of carbon dioxide.
    :cvar SO2_EMISSIONS_PRODUCT: For US Emissions Allowance
        Transactions: A limited authorization issued by the U.S.
        Environmental Protection Agency (EPA) to emit a certain amount
        of sulfur dioxide.
    :cvar STATE_EMISSION_PRODUCT: For US Emissions Allowance
        Transactions: Any emissions allowance or emission reduction
        credit created and promulgated under a U.S. state Scheme.
    :cvar VOLUNTARY_EMISSION_PRODUCT: For US Emissions Allowance
        Transactions: Any emissions allowance, emission credit,
        emissions offset or emissions reduction credit created or issued
        under a voluntary Scheme.
    :cvar RENEWABLE_ENERGY_CERTIFICATE: For US Renewable Energy
        Certificate Transactions: A Renewable Energy Certificate (“REC”)
        represents the environmental, social and other non-power
        qualities of generation of 1 megawatt-hour (MWh) of electricity
        from an eligible renewable energy resource.
    :cvar AUSCARBON_CREDIT_UNIT: Australia Green Energy: Australian
        Carbon Credit Unit.
    :cvar AUSCARBON_UNIT: Australia Green Energy: Australian Carbon
        Unit.
    :cvar AUSENERGY_SAVING_CERTIFICATE: Australia Green Energy: Energy
        Savings Certificate.
    :cvar AUSLARGE_SCALE_GENERATION_CERTIFICATE: Australia Green Energy:
        Large-scale Generation Certificate.
    :cvar AUSSMALL_SCALE_TECHNOLOGY_CERTIFICATE: Australia Green Energy:
        Small-scale Technology Certificate.
    :cvar AUSVICTORIAN_ENERGY_EFFICIENCY_CERTIFICATE: Australia Green
        Energy: Victorian Energy Efficiency Certificate.
    :cvar MXCCFECRTINTLODS: Mexico CCFE CRT INTLODS Physical
        Certificates.
    :cvar NZEMISSIONS_UNITS: New Zealand Emissions Units.
    :cvar UKRENEWABLE_OBLIGATION_CERTIFICATE: United Kingdom Ofgem
        Renewable Obligation Certificate.
    """

    EUALLOWANCE = "EUAllowance"
    EUCREDIT = "EUCredit"
    ALTERNATIVE_ALLOWANCE = "AlternativeAllowance"
    NOXEMISSIONS_PRODUCT = "NOXEmissionsProduct"
    REGIONAL_EMISSIONS_PRODUCT = "RegionalEmissionsProduct"
    RGGIEMISSIONS_PRODUCT = "RGGIEmissionsProduct"
    SO2_EMISSIONS_PRODUCT = "SO2EmissionsProduct"
    STATE_EMISSION_PRODUCT = "StateEmissionProduct"
    VOLUNTARY_EMISSION_PRODUCT = "VoluntaryEmissionProduct"
    RENEWABLE_ENERGY_CERTIFICATE = "RenewableEnergyCertificate"
    AUSCARBON_CREDIT_UNIT = "AUSCarbonCreditUnit"
    AUSCARBON_UNIT = "AUSCarbonUnit"
