class FeeElectionEnum(Enum):
    """
    Defines the fee type.

    :cvar FLAT_FEE: The product of (i) the Break Fee Rate multiplied by
        (ii) the Equity Notional Amount corresponding to the Early
        Termination Portion.
    :cvar AMORTIZED_FEE: The product of (i) the Break Fee Rate
        multiplied by (ii) the Equity Notional Amount corresponding to
        the Early Termination Portion multiplied by (iii) the number of
        days from the Early Termination Date to the later of the
        Termination Date or the Cash Settlement Payment Date
        corresponding to the latest Valuation Date.
    :cvar FUNDING_FEE: The product of (i) the Equity Notional Amount
        corresponding to the Early Termination Portion multiplied by
        (ii) the Break Funding Rate multiplied by (iii) the number of
        days from the Early Termination Date to the next scheduled Reset
        Date divided by (iv) a number equivalent to the denominator of
        the Day Count Fraction applicable to the Floating Rate Option.
    :cvar FLAT_FEE_AND_FUNDING_FEE: Both Flat Fee and Funding Fee are
        applicable.
    :cvar AMORTIZED_FEE_AND_FUNDING_FEE: Amortized Fee and Funding Fee
        are applicable.
    """

    FLAT_FEE = "FlatFee"
    AMORTIZED_FEE = "AmortizedFee"
    FUNDING_FEE = "FundingFee"
    FLAT_FEE_AND_FUNDING_FEE = "FlatFeeAndFundingFee"
    AMORTIZED_FEE_AND_FUNDING_FEE = "AmortizedFeeAndFundingFee"


