@dataclass(kw_only=True)
class FloatingAmountProvisions:
    """
    :ivar waccap_interest_provision: As specified by the ISDA Supplement
        for use with trades on mortgage-backed securities, "WAC Cap"
        means a weighted average coupon or weighted average rate cap
        provision (however defined in the Underlying Instruments) of the
        Underlying Instruments that limits, increases or decreases the
        interest rate or interest entitlement, as set out in the
        Underlying Instruments on the Effective Date without regard to
        any subsequent amendment The presence of the element with value
        set to 'true' signifies that the provision is applicable. From a
        usage standpoint, this provision is typically applicable in the
        case of CMBS and not applicable in case of RMBS trades.
    :ivar step_up_provision: As specified by the ISDA Standard Terms
        Supplement for use with trades on mortgage-backed securities.
        The presence of the element with value set to 'true' signifies
        that the provision is applicable. If applicable, the applicable
        step-up terms are specified as part of that ISDA Standard Terms
        Supplement. From a usage standpoint, this provision is typically
        applicable in the case of RMBS and not applicable in case of
        CMBS trades.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

