class FxBarrierDirectionEnum(Enum):
    """
    The specification of whether the direction of a barrier within an FX
    OTC option is Down or Up.

    :cvar DOWN: The barrier is triggered if the observed rate is at or
        below the barrier level during the period of observation, or at
        the time of observation.
    :cvar UP: The barrier is triggered if the observed rate is at or
        above the barrier level during the period of observation, or at
        the time of observation.
    """

    DOWN = "Down"
    UP = "Up"


class FxBarrierScopeEnum(Enum):
    """
    The specification of whether a barrier has effect for the current
    expiry period, or globally to the whole product.

    :cvar GLOBAL: The barrier has effect for the expiry period in which
        it is triggered, and all subsequent periods.
    :cvar PER_EXPIRY: The barrier has effect only for the expiry period
        in which it is triggered.
    """

    GLOBAL = "Global"
    PER_EXPIRY = "PerExpiry"


class FxBarrierStyleEnum(Enum):
    """
    Defines the barrier observation style i.e. continuous (American) or
    discrete (Euriopean).

    :cvar AMERICAN: The barrier is observed continuously through the
        observation period.
    :cvar EUROPEAN: The barrier is observed on a discrete expiry date,
        or (in the case of a multi-phase product) series of expiry
        dates.
    """

    AMERICAN = "American"
    EUROPEAN = "European"


class FxBarrierTypeEnum(Enum):
    """
    The specification of whether a barrier within an FX OTC option is a
    knockin or knockout.

    :cvar KNOCKIN: The option exists if the spot rate is at or above, or
        at or below the barrier level according to the specified barrier
        direction.
    :cvar KNOCKOUT: The option ceases to exist if the spot rate is at or
        above, or at or below the barrier level according to the
        specified barrier direction.
    :cvar REVERSE_KNOCKIN: DEPRECATE: Option exists once the barrier is
        hit. The trigger rate is in-the money in relation to the strike
        rate.
    :cvar REVERSE_KNOCKOUT: DEPRECATE: Option ceases to exist once the
        barrier is hit. The trigger rate is in-the money in relation to
        the strike rate.
    """

    KNOCKIN = "Knockin"
    KNOCKOUT = "Knockout"
    REVERSE_KNOCKIN = "ReverseKnockin"
    REVERSE_KNOCKOUT = "ReverseKnockout"


class FxBarrierTypeSimpleEnum(Enum):
    """
    Defines the outcome in the event that the barrier is triggered i.e.
    whether the product becomes active (Knockin) or is extinguished
    (Knockout).

    Omitting superseded values ReverseKnock[in|out].

    :cvar KNOCKIN: The option exists if the spot rate is at or above, or
        at or below the barrier level according to the specified barrier
        direction.
    :cvar KNOCKOUT: The option ceases to exist if the spot rate is at or
        above, or at or below the barrier level according to the
        specified barrier direction.
    """

    KNOCKIN = "Knockin"
    KNOCKOUT = "Knockout"


