class FxTargetStyleEnum(Enum):
    """
    Defines the method for calculating the gain in the period where the
    Target Knock-Out event occurs (Exact, Exclusive, Inclusive).

    :cvar EXACT: The gain for the knockout period is adjusted to yield a
        final accumulated value equal to the target level.
    :cvar EXCLUSIVE: The gain for the knockout period is adjusted to
        zero i.e. the target yields zero value in the final period.
    :cvar INCLUSIVE: The gain for the knockout period is equal to the
        whole benefit of the final fixing over spot i.e. the final
        accumulated value may exceed the target level.
    """

    EXACT = "Exact"
    EXCLUSIVE = "Exclusive"
    INCLUSIVE = "Inclusive"


