class InflationCalculationMethodEnum(Enum):
    """
    Code values for different ways of using inflation indexes in formulas.

    :cvar RATIO: (Inflation Index Final / Inflation Index Base).
        Inflation Index Final is inflation index for Reference Month
        that is the Lag number of months prior to Payment Date (subject
        to interpolation). Inflation Index Base subject to the
        Calculation Style. Used in inflation asset swaps to calculate
        the inflation coupons and principal exchange.
    :cvar RETURN: (Inflation Index Final / Inflation Index Base -1).
        Inflation Index Final is the inflation index for Reference Month
        that is the Lag number of months prior to Payment Date (subject
        to interp). Inflation Index Base subject to the Calculation
        Style. Used in market standard ZC Inflation swaps.
    :cvar SPREAD: Inflation Index Final - Inflation Index Base).
        Inflation Index Final is Index for Ref month the Lag months
        prior to Payment Date (subject to interp). Inflation Index Base
        subject to the Calculation Style. Typically used for fixing
        locks.
    """

    RATIO = "Ratio"
    RETURN = "Return"
    SPREAD = "Spread"


class InflationCalculationStyleEnum(Enum):
    """
    Code values for different styles of ways of calculation methods.

    :cvar YEAR_ON_YEAR: YearOnYear means Inflation Index Base is the
        inflation index for Reference Month that is 12 months prior to
        Inflation Index Final (subject to interpolation). Inflation
        Index Base is cashflow dependent.
    :cvar ZERO_COUPON: ZeroCoupon means Inflation Index Base used in the
        CalculationMethod is the inflation index for the Reference Month
        that is the lag number of months prior to Effective Date in the
        case of a swap, or Bond Interest Accrual Date in the case of an
        Asset Swap (subject to interpolation). Inflation Index Base has
        the same value for each inflation cashflow and Principal
        Exchange calculation within the trade.
    """

    YEAR_ON_YEAR = "YearOnYear"
    ZERO_COUPON = "ZeroCoupon"


