class OptionTypeEnum(Enum):
    """
    Specifies the type of the option.

    :cvar PUT: A put option gives the holder the right to sell the
        underlying asset by a certain date for a certain price.
    :cvar CALL: A call option gives the holder the right to buy the
        underlying asset by a certain date for a certain price.
    :cvar PAYER: A "payer" option: If you buy a "payer" option you have
        the right but not the obligation to enter into the underlying
        swap transaction as the "fixed" rate/price payer and receive
        float.
    :cvar RECEIVER: A receiver option: If you buy a "receiver" option
        you have the right but not the obligation to enter into the
        underlying swap transaction as the "fixed" rate/price receiver
        and pay float.
    :cvar STRADDLE: A straddle strategy.
    """

    PUT = "Put"
    CALL = "Call"
    PAYER = "Payer"
    RECEIVER = "Receiver"
    STRADDLE = "Straddle"


