@dataclass(kw_only=True)
class PcdeliverableObligationCharac:
    """
    :ivar applicable: Indicates whether the provision is applicable.
    :ivar partial_cash_settlement: Specifies whether either 'Partial
        Cash Settlement of Assignable Loans', 'Partial Cash Settlement
        of Consent Required Loans' or 'Partial Cash Settlement of
        Participations' is applicable. If this element is specified and
        Assignable Loan is a Deliverable Obligation Chracteristic, any
        Assignable Loan that is deliverable, but where a non-receipt of
        Consent by the Physical Settlement Date has occurred, the Loan
        can be cash settled rather than physically delivered. If this
        element is specified and Consent Required Loan is a Deliverable
        Obligation Characterisitc, any Consent Required Loan that is
        deliverable, but where a non-receipt of Consent by the Physical
        Settlement Date has occurred, the Loan can be cash settled
        rather than physically delivered. If this element is specified
        and Direct Loan Participation is a Deliverable Obligation
        Characterisitic, any Participation that is deliverable, but
        where this participation has not been effected (has not come
        into effect) by the Physical Settlement Date, the participation
        can be cash settled rather than physically delivered.
    """

    class Meta:
        name = "PCDeliverableObligationCharac"
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    applicable: bool = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    partial_cash_settlement: None | bool = field(
        default=None,
        metadata={
            "name": "partialCashSettlement",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


