class RepoDurationEnum(Enum):
    """
    A duration code for a Repo or Securities Lending transaction.

    There are many business and market rules that are derived from the
    duration of the transaction.

    :cvar OPEN: Indicates that the contract is an open arrangement,
        which remains in effect unless or until terminated at the option
        of one or both parties. Repo business rule: When the repo is
        'Open', the forward leg MUST NOT be specified. SBL business
        rule: When a security lending arrangement is 'Open', the
        termination block ('termination/settlementDate') MUST NOT be
        specified.
    :cvar TERM: Indicates that a contract is a regular term contract,
        with a start date and an end date. Repo business rule: When the
        repo is 'Term', both spot and forward legs MUST be specified.
        SBL business rule: When a security lending arrangement is
        'Term', both the initiation block ('initiation/settlementDate')
        and the termination block ('termination/settlementDate') MUST be
        specified.
    :cvar OVERNIGHT: Indicates that a contract is classified as
        overnight, meaning that there is one business day difference
        between the start and end date of the contract. Business rule:
        When the repo is overnight, the number of business days between
        the spot and forward value dates must be one. Forward leg must
        be specified.
    """

    OPEN = "Open"
    TERM = "Term"
    OVERNIGHT = "Overnight"


