class SettlementTypeEnum(Enum):
    """
    Shows how the transaction is to be settled when it is exercised.

    :cvar CASH: The intrinsic value of the option will be delivered by
        way of a cash settlement amount determined, (i) by reference to
        the differential between the strike price and the settlement
        price; or (ii) in accordance with a bilateral agreement between
        the parties
    :cvar PHYSICAL: The securities underlying the transaction will be
        delivered by (i) in the case of a call, the seller to the buyer,
        or (ii) in the case of a put, the buyer to the seller versus a
        settlement amount equivalent to the strike price per share
    :cvar ELECTION: Allow Election of either Cash or Physical settlement
    :cvar CASH_OR_PHYSICAL: Allow use of either Cash or Physical
        settlement without prior Election
    """

    CASH = "Cash"
    PHYSICAL = "Physical"
    ELECTION = "Election"
    CASH_OR_PHYSICAL = "CashOrPhysical"


class ShareExtraordinaryEventEnum(Enum):
    """
    Defines the consequences of extraordinary events relating to the
    underlying.

    :cvar ALTERNATIVE_OBLIGATION: The trade continues such that the
        underlying now consists of the New Shares and/or the Other
        Consideration, if any, and the proceeds of any redemption, if
        any, that the holder of the underlying Shares would have been
        entitled to.
    :cvar CANCELLATION_AND_PAYMENT: The trade is cancelled and a
        cancellation fee will be paid by one party to the other.
    :cvar OPTIONS_EXCHANGE: The trade will be adjusted by the
        Calculation Agent in accordance with the adjustments made by any
        exchange on which options on the underlying are listed.
    :cvar CALCULATION_AGENT: The Calculation Agent will determine what
        adjustment is required to offset any change to the economics of
        the trade. If the Calculation Agent cannot achieve this, the
        trade goes to Cancellation and Payment with the Calculation
        Agent deciding on the value of the cancellation fee. Adjustments
        may not be made to account solely for changes in volatility,
        expected dividends, stock loan rate or liquidity.
    :cvar MODIFIED_CALCULATION_AGENT: The Calculation Agent will
        determine what adjustment is required to offset any change to
        the economics of the trade. If the Calculation Agent cannot
        achieve this, the trade goes to Cancellation and Payment with
        the Calculation Agent deciding on the value of the cancellation
        fee. Adjustments to account for changes in volatility, expected
        dividends, stock loan rate or liquidity are allowed.
    :cvar PARTIAL_CANCELLATION_AND_PAYMENT: Applies to Basket
        Transactions. The portion of the Basket made up by the affected
        Share will be cancelled and a cancellation fee will be paid from
        one party to the other. The remainder of the trade continues.
    :cvar COMPONENT: If this is a Share-for-Combined merger event
        (Shares are replaced with New Shares and Other Consideration),
        then different treatment can be applied to each component if the
        parties have specified this.
    """

    ALTERNATIVE_OBLIGATION = "AlternativeObligation"
    CANCELLATION_AND_PAYMENT = "CancellationAndPayment"
    OPTIONS_EXCHANGE = "OptionsExchange"
    CALCULATION_AGENT = "CalculationAgent"
    MODIFIED_CALCULATION_AGENT = "ModifiedCalculationAgent"
    PARTIAL_CANCELLATION_AND_PAYMENT = "PartialCancellationAndPayment"
    COMPONENT = "Component"


