class SpecifiedPriceEnum(Enum):
    """
    The Specified Price in respect of a Transaction and a Commodity
    Reference Price.

    :cvar AFTERNOON: The Specified Price shall be the Afternoon fixing
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar ASK: The Specified Price shall be the Ask price reported in or
        by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar BID: The Specified Price shall be the Bid price reported in or
        by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar CLOSING: The Specified Price shall be the Closing price
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar HIGH: The Specified Price shall be the High price reported in
        or by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar INDEX: The Specified Price shall be the Index price reported
        in or by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar MEAN_OF_BID_AND_ASK: The Specified Price shall be the Average
        of the Bid and Ask prices reported in or by the relevant Price
        Source as specified in the relevant Confirmation.
    :cvar LOCATIONAL_MARGINAL: The Specified Price shall be the
        Locational Marginal price reported in or by the relevant Price
        Source as specified in the relevant Confirmation.
    :cvar LOW: The Specified Price shall be the Low price reported in or
        by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar MARGINAL_HOURLY: The Specified Price shall be the Marginal
        Hourly price reported in or by the relevant Price Source as
        specified in the relevant Confirmation.
    :cvar MARKET_CLEARING: The Specified Price shall be the Market
        Clearing price reported in or by the relevant Price Source as
        specified in the relevant Confirmation.
    :cvar MEAN_OF_HIGH_AND_LOW: The Specified Price shall be the Average
        of the High and Low prices reported in or by the relevant Price
        Source as specified in the relevant Confirmation.
    :cvar MORNING: The Specified Price shall be the Morning fixing
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar OFFICIAL: The Specified Price shall be the Official price
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar OPENING: The Specified Price shall be the Opening price
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar OSP: The Specified Price shall be the Official Settlement
        Price reported in or by the relevant Price Source as specified
        in the relevant Confirmation.
    :cvar SETTLEMENT: The Specified Price shall be the Settlement price
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar SPOT: The Specified Price shall be the Spot price reported in
        or by the relevant Price Source as specified in the relevant
        Confirmation.
    :cvar MIDPOINT: The Specified Price shall be the Average of the
        Midpoint of prices reported in or by the relevant Price Source
        as specified in the relevant Confirmation.
    :cvar NATIONAL_SINGLE: The Specified Price shall be the National
        Single price reported in or by the relevant Price Source as
        specified in the relevant Confirmation.
    :cvar WEIGHTED_AVERAGE: The Specified Price shall be the Volume
        Weighted Average of prices effective on the Pricing Date
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    :cvar UN_WEIGHTED_AVERAGE: The Specified Price shall be the Non-
        volume Weighted Average of prices effective on the Pricing Date
        reported in or by the relevant Price Source as specified in the
        relevant Confirmation.
    """

    AFTERNOON = "Afternoon"
    ASK = "Ask"
    BID = "Bid"
    CLOSING = "Closing"
    HIGH = "High"
    INDEX = "Index"
    MEAN_OF_BID_AND_ASK = "MeanOfBidAndAsk"
    LOCATIONAL_MARGINAL = "LocationalMarginal"
    LOW = "Low"
    MARGINAL_HOURLY = "MarginalHourly"
    MARKET_CLEARING = "MarketClearing"
    MEAN_OF_HIGH_AND_LOW = "MeanOfHighAndLow"
    MORNING = "Morning"
    OFFICIAL = "Official"
    OPENING = "Opening"
    OSP = "OSP"
    SETTLEMENT = "Settlement"
    SPOT = "Spot"
    MIDPOINT = "Midpoint"
    NATIONAL_SINGLE = "NationalSingle"
    WEIGHTED_AVERAGE = "WeightedAverage"
    UN_WEIGHTED_AVERAGE = "UnWeightedAverage"


