class StubPeriodTypeEnum(Enum):
    """
    Element to define how to deal with a none standard calculation period
    within a swap stream.

    :cvar SHORT_INITIAL: If there is a non regular period remaining it
        is left shorter than the streams calculation period frequency
        and placed at the start of the stream
    :cvar SHORT_FINAL: If there is a non regular period remaining it is
        left shorter than the streams calculation period frequency and
        placed at the end of the stream
    :cvar LONG_INITIAL: If there is a non regular period remaining it is
        placed at the start of the stream and combined with the adjacent
        calculation period to give a long first calculation period
    :cvar LONG_FINAL: If there is a non regular period remaining it is
        placed at the end of the stream and combined with the adjacent
        calculation period to give a long last calculation period
    """

    SHORT_INITIAL = "ShortInitial"
    SHORT_FINAL = "ShortFinal"
    LONG_INITIAL = "LongInitial"
    LONG_FINAL = "LongFinal"


