@dataclass(kw_only=True)
class Tranche:
    """
    This type represents a CDS Tranche.

    :ivar attachment_point: Lower bound percentage of the loss that the
        Tranche can endure, expressed as a decimal. An attachment point
        of 5% would be represented as 0.05. The difference between
        Attachment and Exhaustion points is call the width of the
        Tranche. A schema facet to constraint the value between 0 to 1
        will be introduced in FpML 4.3.
    :ivar exhaustion_point: Upper bound percentage of the loss that the
        Tranche can endure, expressed as a decimal. An exhaustion point
        of 5% would be represented as 0.05. The difference between
        Attachment and Exhaustion points is call the width of the
        Tranche. A schema facet to constraint the value between 0 to 1
        will be introduced in FpML 4.3.
    :ivar incurred_recovery_applicable: Outstanding Swap Notional Amount
        is defined at any time on any day, as the greater of: (a) Zero;
        If Incurred Recovery Amount Applicable: (b) The Original Swap
        Notional Amount minus the sum of all Incurred Loss Amounts and
        all Incurred Recovery Amounts (if any) determined under this
        Confirmation at or prior to such time.Incurred Recovery Amount
        not populated: (b) The Original Swap Notional Amount minus the
        sum of all Incurred Loss Amounts determined under this
        Confirmation at or prior to such time.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    attachment_point: Decimal = field(
        metadata={
            "name": "attachmentPoint",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    exhaustion_point: Decimal = field(
        metadata={
            "name": "exhaustionPoint",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    incurred_recovery_applicable: None | bool = field(
        default=None,
        metadata={
            "name": "incurredRecoveryApplicable",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


