class TriggerConditionEnum(Enum):
    """
    The specification of whether a payout will occur on an option depending
    upon whether the spot rate is at or above or at or below the trigger
    rate.

    :cvar AT_OR_ABOVE: The spot rate must be greater than or equal to
        the trigger rate.
    :cvar AT_OR_BELOW: The spot rate must be less than or equal to the
        trigger rate.
    :cvar ABOVE: DEPRECATE: The spot rate must be greater than or equal
        to the trigger rate.
    :cvar BELOW: DEPRECATE: The spot rate must be less than or equal to
        the trigger rate.
    """

    AT_OR_ABOVE = "AtOrAbove"
    AT_OR_BELOW = "AtOrBelow"
    ABOVE = "Above"
    BELOW = "Below"


class TriggerTimeTypeEnum(Enum):
    """
    The time of day which would be considered for valuing the knock event.

    :cvar CLOSING: The close of trading on a day would be considered for
        valuation.
    :cvar ANYTIME: At any time during the Knock Determination period
        (continuous barrier).
    """

    CLOSING = "Closing"
    ANYTIME = "Anytime"


class TriggerTypeEnum(Enum):
    """
    The specification of whether an option will trigger or expire depending
    upon whether the spot rate is above or below the barrier rate.

    :cvar EQUAL_OR_LESS: The underlyer price must be equal to or less
        than the Trigger level.
    :cvar EQUAL_OR_GREATER: The underlyer price must be equal to or
        greater than the Trigger level.
    :cvar EQUAL: The underlyer price must be equal to the Trigger level.
    :cvar LESS: The underlyer price must be less than the Trigger level.
    :cvar GREATER: The underlyer price must be greater than the Trigger
        level.
    """

    EQUAL_OR_LESS = "EqualOrLess"
    EQUAL_OR_GREATER = "EqualOrGreater"
    EQUAL = "Equal"
    LESS = "Less"
    GREATER = "Greater"


