@dataclass(kw_only=True)
class VolatilityCap:
    """
    :ivar applicable: Indicates whether the volatility cap is applicable
        in accordance with the ISDA 2011 Equity Derivatives Definitions.
        Setting the element 'applicable' to 'False' - means No
        Volatility Cap and no 'totalVolatilityCap' or
        'volatilityCapFactor' should be provided. Setting the element
        'applicable' to 'True' - means Volatility Cap election, then
        'totalVolatilityCap' or 'volatilityCapFactor' should be
        provided, otherwise it defaults to volatilityCapFactor=2.5.
    :ivar total_volatility_cap: Volatility Cap Amount in accordance with
        the ISDA 2011 Equity Derivatives Definitions. This means the
        Volatility Cap Amount election is a number.
    :ivar volatility_cap_factor: Volatility Cap Factor in accordance
        with the ISDA 2011 Equity Derivatives Definitions. This means
        the Volatility Cap Amount election is Calculated VolCapAmt
        ('volatilityCapFactor' * 'volatilityStrikePrice'). By specifying
        a decimal for 'volatilityCapFactor', means the default value of
        2.5 does not apply.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    applicable: bool = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    total_volatility_cap: None | Decimal = field(
        default=None,
        metadata={
            "name": "totalVolatilityCap",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
            "min_exclusive": Decimal("0"),
        },
    )
    volatility_cap_factor: None | Decimal = field(
        default=None,
        metadata={
            "name": "volatilityCapFactor",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
            "min_exclusive": Decimal("0"),
        },
    )


