@dataclass(kw_only=True)
class MultipleExercise:
    """
    A type defining multiple exercises.

    As defining in the 2000 ISDA Definitions, Section 12.4. Multiple
    Exercise, the buyer of the option has the right to exercise all or less
    than all the unexercised notional amount of the underlying swap on one
    or more days in the exercise period, but on any such day may not
    exercise less than the minimum notional amount or more than the maximum
    notional amount, and if an integral multiple amount is specified, the
    notional exercised must be equal to or, be an integral multiple of, the
    integral multiple amount.

    :ivar notional_reference: A pointer style reference to the
        associated notional schedule defined elsewhere in the document.
        This element has been made optional as part of its integration
        in the OptionBaseExtended, because not required for the options
        on securities.
    :ivar integral_multiple_amount: A notional amount which restricts
        the amount of notional that can be exercised when partial
        exercise or multiple exercise is applicable. The integral
        multiple amount defines a lower limit of notional that can be
        exercised and also defines a unit multiple of notional that can
        be exercised, i.e. only integer multiples of this amount can be
        exercised.
    :ivar minimum_notional_amount: The minimum notional amount that can
        be exercised on a given exercise date. See multipleExercise.
    :ivar minimum_number_of_options: The minimum number of options that
        can be exercised on a given exercise date.
    :ivar maximum_notional_amount: The maximum notional amount that can
        be exercised on a given exercise date.
    :ivar maximum_number_of_options: The maximum number of options that
        can be exercised on a given exercise date. If the number is not
        specified, it means that the maximum number of options
        corresponds to the remaining unexercised options.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    notional_reference: list[NotionalReference] = field(
        default_factory=list,
        metadata={
            "name": "notionalReference",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    integral_multiple_amount: None | Decimal = field(
        default=None,
        metadata={
            "name": "integralMultipleAmount",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
