@dataclass(kw_only=True)
class PendingPayment(PaymentBase):
    """
    A structure representing a pending dividend or coupon payment.

    :ivar payment_date: The date that the dividend or coupon is due.
    :ivar amount: The amount of the dividend or coupon payment. Value of
        dividends or coupon between ex and pay date. Stock: if we are
        between ex-date and pay-date and the dividend is payable under
        the swap, then this should be the ex-div amount * # of
        securities. Bond: regardless of where we are vis-a-vis resets:
        (coupon % * face of bonds on swap * (bond day count fraction
        using days last coupon pay date of the bond through today).
    :ivar accrued_interest: Accrued interest on the dividend or coupon
        payment. When the TRS is structured to pay a dividend or coupon
        on reset after payable date, you may earn interest on these
        amounts. This field indicates the interest accrued on
        dividend/coupon from pay date to statement date. This will only
        apply to a handful of agreements where dividendss are held to
        the next reset AND you receive/pay interest on unpaid amounts.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    payment_date: XmlDate = field(
        metadata={
            "name": "paymentDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    amount: Money = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    accrued_interest: None | Money = field(
        default=None,
        metadata={
            "name": "accruedInterest",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


