@dataclass(kw_only=True)
class ResetDates:
    """
    A type defining the parameters used to generate the reset dates
    schedule and associated fixing dates.

    The reset dates are determined relative to the calculation periods
    schedules dates.

    :ivar calculation_period_dates_reference: A pointer style reference
        to the associated calculation period dates component defined
        elsewhere in the document.
    :ivar reset_relative_to: Specifies whether the reset dates are
        determined with respect to each adjusted calculation period
        start date or adjusted calculation period end date. If the reset
        frequency is specified as daily this element must not be
        included.
    :ivar initial_fixing_date:
    :ivar fixing_dates: Specifies the fixing date relative to the reset
        date in terms of a business days offset and an associated set of
        financial business centers. Normally these offset calculation
        rules will be those specified in the ISDA definition for the
        relevant floating rate index (ISDA's Floating Rate Option).
        However, non-standard offset calculation rules may apply for a
        trade if mutually agreed by the principal parties to the
        transaction. The href attribute on the dateRelativeTo element
        should reference the id attribute on the resetDates element.
    :ivar rate_cut_off_days_offset: Specifies the number of business
        days before the period end date when the rate cut-off date is
        assumed to apply. The financial business centers associated with
        determining the rate cut-off date are those specified in the
        reset dates adjustments. The rate cut-off number of days must be
        a negative integer (a value of zero would imply no rate cut off
        applies in which case the rateCutOffDaysOffset element should
        not be included). The relevant rate for each reset date in the
        period from, and including, a rate cut-off date to, but
        excluding, the next applicable period end date (or, in the case
        of the last calculation period, the termination date) will
        (solely for purposes of calculating the floating amount payable
        on the next applicable payment date) be deemed to be the
        relevant rate in effect on that rate cut-off date. For example,
        if rate cut-off days for a daily averaging deal is -2 business
        days, then the refix rate applied on (period end date - 2 days)
        will also be applied as the reset on (period end date - 1 day),
        i.e. the actual number of reset dates remains the same but from
        the rate cut-off date until the period end date, the same refix
        rate is applied. Note that in the case of several calculation
        periods contributing to a single payment, the rate cut-off is
        assumed only to apply to the final calculation period
        contributing to that payment. The day type associated with the
        offset must imply a business days offset.
    :ivar reset_frequency: The frequency at which reset dates occur. In
        the case of a weekly reset frequency, also specifies the day of
        the week that the reset occurs. If the reset frequency is
        greater than the calculation period frequency then this implies
        that more than one reset date is established for each
        calculation period and some form of rate averaging is
        applicable.
    :ivar reset_dates_adjustments: The business day convention to apply
        to each reset date if it would otherwise fall on a day that is
        not a business day in the specified financial business centers.
    :ivar id:
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    calculation_period_dates_reference: CalculationPeriodDatesReference = (
        field(
            metadata={
                "name": "calculationPeriodDatesReference",
                "type": "Element",
                "namespace": "http://www.fpml.org/FpML-5/confirmation",
            }
        )
    )
    reset_relative_to: None | ResetRelativeToEnum = field(
        default=None,
        metadata={
            "name": "resetRelativeTo",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    initial_fixing_date: None | RelativeDateOffset = field(
        default=None,
        metadata={
            "name": "initialFixingDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    fixing_dates: RelativeDateOffset = field(
        metadata={
            "name": "fixingDates",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    rate_cut_off_days_offset: None | Offset = field(
        default=None,
        metadata={
            "name": "rateCutOffDaysOffset",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    reset_frequency: ResetFrequency = field(
        metadata={
            "name": "resetFrequency",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
