@dataclass(kw_only=True)
class WeatherLeg(FinancialSwapLeg):
    """
    A weather leg of a Commodity Swap defines Weather Index Swap
    transactions.

    Weather Index Swap transactions are OTC derivative transactions which
    settle financially based on an index calculated from observations of
    temperature, precipitation and other weather-related measurements at
    weather stations throughout the world. Sub-Annex C of the 2005 ISDA
    Commodity Definitions provides definitions and terms for a number of
    types of weather indices. These indices include: HDD (heating degree
    days), CDD (cooling degree days), CPD (critical precipitation days).
    Weather Index Swap transactions result in a cash flow to one of the two
    counterparties each Calculation Period depending on the relationship
    between the Settlement Level and the Weather Index Level. A Weather
    Index swap transaction always consists of a commodity swap element as a
    parent to two weatherLeg elements.

    :ivar weather_index_level: Defining the Weather Index Level or
        Weather Index Strike Level.
    :ivar weather_calculation_periods:
    :ivar weather_calculation_periods_reference:
    :ivar weather_notional_amount: Defines the price per weather index
        unit.
    :ivar calculation: Defines details relevant to the calculation of
        the aggregate weather index amount.
    :ivar payment_dates: The Payment Dates of the trade relative to the
        Calculation Periods or Calculation Date
    :ivar weather_index_data: Specifies where the data (e.g. CPD) have
        been collected, an actual physical reference point (weather
        station) and various fall back arrangements.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

