@dataclass(kw_only=True)
class LoanTradingCostOfCarry:
    """
    A structure that incorporates elements of an accrual calculation, for
    the purpose of defining cost-of-carry.

    :ivar amount: The amount of cost of carry accrued for the given loan
        contract. Funded Amount * Price + (100-Price) * Unfunded -
        (100-Price) * Paydown - Non-Recurring Fees.
    :ivar payer_party_reference: A reference to the party responsible
        for the allocation.
    :ivar receiver_party_reference: A reference to the party that has
        been allocated to.
    :ivar accrual: Details of the accrual schedule in support of the
        cost of carry amount: The commencement amount is the calculated
        'value' of the asset being purchased/sold, as of the end of the
        REGULAR settlement period (e.g. at T+7 for Par). This amount
        takes into account ALL potential adjustments, price and
        utilized/unutilized balances as of the regular settlement date.
        Hence, the reference amount will be the commencement amount and
        the rate will be the average LIBOR (between T+7 and actual
        settlement date). If however, the settlement amount at the END
        of the delay period has changed by more than 25 percent as
        compared to the commencement amount, then the (calculated)
        settlement amount for each applicable day within the delay
        period must be calculated and used to accrue the cost of carry.
        The average LIBOR will still be the applicable rate.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    amount: NonNegativeMoney = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    payer_party_reference: None | PartyReference = field(
        default=None,
        metadata={
            "name": "payerPartyReference",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    receiver_party_reference: None | PartyReference = field(
        default=None,
        metadata={
            "name": "receiverPartyReference",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    accrual: None | LoanTradingCostOfCarryAccrual = field(
        default=None,
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


