@dataclass(kw_only=True)
class Collateral:
    """
    A type for defining the obligations of the counterparty subject to
    credit support requirements.

    :ivar independent_amount: Independent Amount is an amount that
        usually less creditworthy counterparties are asked to provide.
        It can either be a fixed amount or a percentage of the
        Transaction's value. The Independent Amount can be: (i)
        transferred before any trading between the parties occurs (as a
        deposit at a third party's account or with the counterparty) or
        (ii) callable after trading has occurred (typically because a
        downgrade has occurred). In situation (i), the Independent
        Amount is not included in the calculation of Exposure, but in
        situation (ii), it is included in the calculation of Exposure.
        Thus, for situation (ii), the Independent Amount may be
        transferred along with any collateral call. Independent Amount
        is a defined term in the ISDA Credit Support Annex. ("with
        respect to a party, the amount specified as such for that party
        in Paragraph 13; if no amount is specified, zero").
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    independent_amount: IndependentAmount = field(
        metadata={
            "name": "independentAmount",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )


