@dataclass(kw_only=True)
class PeriodicPayment(PaymentBase):
    """
    :ivar payment_frequency: The time interval between regular fixed
        rate payer payment dates.
    :ivar first_period_start_date: The start date of the initial
        calculation period if such date is not equal to the trade’s
        effective date. It must only be specified if it is not equal to
        the effective date. The applicable business day convention and
        business day are those specified in the dateAdjustments element
        within the generalTerms component (or in a transaction
        supplement FpML representation defined within the referenced
        general terms confirmation agreement).
    :ivar first_payment_date: The first unadjusted fixed rate payer
        payment date. The applicable business day convention and
        business day are those specified in the dateAdjustments element
        within the generalTerms component (or in a transaction
        supplement FpML representation defined within the referenced
        general terms confirmation agreement). ISDA 2003 Term: Fixed
        Rate Payer Payment Date
    :ivar last_regular_payment_date: The last regular unadjusted fixed
        rate payer payment date. The applicable business day convention
        and business day are those specified in the dateAdjustments
        element within the generalTerms component (or in a transaction
        supplement FpML representation defined within the referenced
        general terms confirmation agreement). This element should only
        be included if there is a final payment stub, i.e. where the
        last regular unadjusted fixed rate payer payment date is not
        equal to the scheduled termination date. ISDA 2003 Term: Fixed
        Rate Payer Payment Date
    :ivar roll_convention: Used in conjunction with the effectiveDate,
        scheduledTerminationDate, firstPaymentDate,
        lastRegularPaymentDate and paymentFrequency to determine the
        regular fixed rate payer payment dates.
    :ivar fixed_amount: A fixed payment amount. ISDA 2003 Term: Fixed
        Amount
    :ivar fixed_amount_calculation: This element contains all the terms
        relevant to calculating a fixed amount where the fixed amount is
        calculated by reference to a per annum fixed rate. There is no
        corresponding ISDA 2003 Term. The equivalent is Sec 5.1
        "Calculation of Fixed Amount" but this in itself is not a
        defined Term.
    :ivar floating_amount_calculation:
    :ivar adjusted_payment_dates: An optional cashflow-like structure
        allowing the equivalent representation of the periodic fixed
        payments in terms of a series of adjusted payment dates and
        amounts. This is intended to support application integration
        within an organisation and is not intended for use in inter-firm
        communication or confirmations. ISDA 2003 Term: Fixed Rate Payer
        Payment Date
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    payment_frequency: None | Period = field(
        default=None,
        metadata={
            "name": "paymentFrequency",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    first_period_start_date: None | XmlDate = field(
        default=None,
        metadata={
            "name": "firstPeriodStartDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
