@dataclass(kw_only=True)
class TradeAmendmentContent(AbstractEvent):
    """
    A structure describing a negotiated amendment.

    :ivar trade: A full description of the amended trade (i.e. the trade
        after the amendment).
    :ivar agreement_date: The date on which the change was agreed.
    :ivar execution_date_time: The date and time at which the negotiated
        change to the terms of the original contract was agreed, such as
        via telephone or electronic trading system (i.e., agreement
        date/time).
    :ivar effective_date: The date on which the change become effective.
    :ivar notional_change: Indication as to whether the transaction is
        an increase or decrease of notional of a derivative contract.
        Only applies when there is change in notional for a derivative
        contract
    :ivar change_in_notional: The change in notional amount for a prior
        report as a result of this event. The current notional will be
        reported in the trade itself. This corresponds to MiFIR Nominal
        or Monetary amount values; these can be distinguished by the
        esmaNotionalType indicator.
    :ivar change_in_number_of_options: The change in nominal amount from
        a prior report as a result of this event. The current number of
        options will be reported in the trade itself. This corresponds
        to the MiFIR "units" value.
    :ivar change_in_quantity: The change in quantity(s) from a prior
        report as a result of this event. The current quantity will be
        reported in the trade itself. This corresponds to the MiFIR
        "units" value.
    :ivar payment: Describes a payment made in settlement of the change.
        Normally there will be a single fee, but there could be
        additional payments such as principal exchanges resulting from
        the termination.
    """

    class Meta:
        target_namespace = "http://www.fpml.org/FpML-5/confirmation"

    trade: Trade = field(
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    agreement_date: XmlDate = field(
        metadata={
            "name": "agreementDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    execution_date_time: None | ExecutionDateTime = field(
        default=None,
        metadata={
            "name": "executionDateTime",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    effective_date: XmlDate = field(
        metadata={
            "name": "effectiveDate",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        }
    )
    notional_change: None | NotionalChangeEnum = field(
        default=None,
        metadata={
            "name": "notionalChange",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    change_in_notional: list[MoneyRef] = field(
        default_factory=list,
        metadata={
            "name": "changeInNotional",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    change_in_number_of_options: list[AmountRef] = field(
        default_factory=list,
        metadata={
            "name": "changeInNumberOfOptions",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    change_in_quantity: list[UnitQuantityRef] = field(
        default_factory=list,
        metadata={
            "name": "changeInQuantity",
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )
    payment: list[Payment] = field(
        default_factory=list,
        metadata={
            "type": "Element",
            "namespace": "http://www.fpml.org/FpML-5/confirmation",
        },
    )


